\begin{equation}
H_{R}^{\cal B} = \text{Tr}_{R^{\otimes m}}\left((q^{\rho})^{\otimes m} {\cal B}\right) = \sum_{Q \vdash m|R|} h_{RQ}^{\cal B} S_{Q}^{*}(A),
\end{equation}

