\begin{equation}
S_{Q}^{*}(A) = \text{Tr}_{Q \in R^{\otimes m}}(q^{\rho})^{\otimes m} = S_{Q}\{p_{k}^{*}\}, \quad p_{k}^{*} = \frac{[kN]}{[k]} = \frac{A^{k} - A^{-k}}{q^{k} - q^{-k}},
